  static async create(ptr: string, transferType: transferType): Promise<GstClockEntry> {
    const instance = new GstClockEntry(ptr, transferType);
    if (transferType === 'full')
      gstclockentryRegistry.register(instance, ptr);
    return instance;
  }
    







 
